  const relevantPhases = busyTransitions
    .filter((entry) => entry.taskId === activeTaskId)
    .map((entry) => entry.phase);

  assert.deepEqual(relevantPhases, ["assistant", "assistant", "tool", "assistant", "tool", "assistant"]);
